import{bQ as a,aL as i,u as t,G as e}from"./chunks/framework.D06dwy5q.js";const c=JSON.parse('{"title":"06｜索引原理","description":"","frontmatter":{},"headers":[],"relativePath":"04.MySQL/06-索引原理.md","filePath":"04.MySQL/06-索引原理.md","lastUpdated":null}'),h={name:"04.MySQL/06-索引原理.md"};function n(l,s,p,d,k,r){return i(),t("div",null,[...s[0]||(s[0]=[e(`<h1 id="_06-索引原理" tabindex="-1">06｜索引原理 <a class="header-anchor" href="#_06-索引原理" aria-label="Permalink to &quot;06｜索引原理&quot;">​</a></h1><p>前面写的查询，表里几行数据时秒回。但表里几百万行后，同样的查询要几秒甚至几十秒。差别在哪？在于有没有索引、索引建得对不对。</p><p>索引是让查询少扫数据的机制。本篇讲索引怎么工作、怎么设计联合索引、什么情况索引会失效。下一篇讲怎么用 EXPLAIN 看查询实际走了什么索引。</p><h2 id="一、没有索引时发生了什么" tabindex="-1">一、没有索引时发生了什么 <a class="header-anchor" href="#一、没有索引时发生了什么" aria-label="Permalink to &quot;一、没有索引时发生了什么&quot;">​</a></h2><p>一张几百万行的 access_logs 表，查某个用户的记录：</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> access_logs </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> user_id </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1001</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p>如果 user_id 上没索引，MySQL 怎么找到这些行？只能从头到尾扫整张表（full table scan），逐行判断 user_id 等不等于 1001。几百万行全扫一遍，几秒就过去了。</p><p>加了索引后，MySQL 不用扫全表，直接通过索引结构定位到 user_id=1001 的行。从&quot;扫几百万行&quot;变成&quot;扫几十行&quot;，毫秒级返回。索引的本质就是这个——提供一条少扫描数据的路径。</p><h2 id="二、b-tree-索引长什么样" tabindex="-1">二、B+Tree：索引长什么样 <a class="header-anchor" href="#二、b-tree-索引长什么样" aria-label="Permalink to &quot;二、B+Tree：索引长什么样&quot;">​</a></h2><p>InnoDB 的索引结构是 B+Tree（B 加树）。不用懂它的算法细节，理解一个关键点：<strong>它让数据按索引列的值排好序，查找时能像翻字典一样快速定位，而不是逐页翻。</strong></p><p>字典按拼音排序，找一个字不用从头翻到尾，按拼音首字母直接跳到那一块。B+Tree 类似——索引列的值在树里排好序，查找时一层层缩小范围，几下就定位到。</p><h3 id="聚簇索引和二级索引" tabindex="-1">聚簇索引和二级索引 <a class="header-anchor" href="#聚簇索引和二级索引" aria-label="Permalink to &quot;聚簇索引和二级索引&quot;">​</a></h3><p>InnoDB 的索引分两种：</p><table tabindex="0"><thead><tr><th>类型</th><th>叶子节点存什么</th><th>怎么用</th></tr></thead><tbody><tr><td>聚簇索引</td><td>主键 + 整行数据</td><td>按主键找，直接拿到整行</td></tr><tr><td>二级索引</td><td>索引列 + 主键值</td><td>按索引列找到主键，可能还要回聚簇索引取整行</td></tr></tbody></table><p>每张表只有一个聚簇索引——就是主键索引，数据本身就按主键顺序存在这棵树里。其他索引都是二级索引，叶子节点存的是&quot;索引列的值 + 对应的主键值&quot;。</p><h3 id="回表" tabindex="-1">回表 <a class="header-anchor" href="#回表" aria-label="Permalink to &quot;回表&quot;">​</a></h3><p>用二级索引查数据时，分两步：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 在二级索引树里找到 user_id=1001 的记录，拿到它的主键 id</span></span>
<span class="line"><span>2. 拿着 id 回聚簇索引树找整行数据</span></span></code></pre></div><p>第二步叫&quot;回表&quot;——回到聚簇索引取整行。回表有开销，多一次树查找。</p><p><strong>回表不是必须的</strong>。如果查询要的列全在二级索引里，不用回聚簇索引，这叫覆盖索引。比如索引是 <code>(user_id, created_at)</code>，查询只要 <code>user_id</code> 和 <code>created_at</code>：</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> user_id, created_at </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> access_logs </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> user_id </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1001</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p>这两个列都在索引里，不用回表，直接返回。EXPLAIN 里看到 <code>Extra: Using index</code> 通常就是覆盖索引。</p><h3 id="主键长度影响所有索引" tabindex="-1">主键长度影响所有索引 <a class="header-anchor" href="#主键长度影响所有索引" aria-label="Permalink to &quot;主键长度影响所有索引&quot;">​</a></h3><p>二级索引的叶子节点要存主键值。主键越长（比如用 UUID、长字符串），每个二级索引的叶子节点就越大，索引占空间多、扫描慢。<strong>生产表主键用自增整型</strong>（<code>BIGINT UNSIGNED AUTO_INCREMENT</code>），短、递增、紧凑。</p><h2 id="三、联合索引和最左前缀" tabindex="-1">三、联合索引和最左前缀 <a class="header-anchor" href="#三、联合索引和最左前缀" aria-label="Permalink to &quot;三、联合索引和最左前缀&quot;">​</a></h2><p>索引可以建在多个列上，叫联合索引：</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">KEY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> idx_user_time (user_id, created_at)</span></span></code></pre></div><p>这个索引同时管 <code>user_id</code> 和 <code>created_at</code> 的组合查询。但它有个&quot;最左前缀&quot;规则——<strong>联合索引 <code>(A, B)</code> 能用于查 A、查 A+B，但不能用于只查 B</strong>。</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> user_id </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1001</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                              -- ✓ 用到索引（最左列）</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> user_id </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1001</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> AND</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> created_at </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;...&#39;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     -- ✓ 用到索引</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> created_at </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;...&#39;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                         -- ✗ 用不上（跳过了 user_id）</span></span></code></pre></div><p>为什么？B+Tree 按联合索引的列顺序排序——先按 user_id 排，user_id 相同再按 created_at 排。跳过 user_id 直接查 created_at，树里 created_at 是分散的，没法定位。</p><h3 id="联合索引的列顺序" tabindex="-1">联合索引的列顺序 <a class="header-anchor" href="#联合索引的列顺序" aria-label="Permalink to &quot;联合索引的列顺序&quot;">​</a></h3><p>列顺序决定了哪些查询能用上索引。原则：</p><ul><li><strong>等值条件的列放前面</strong>（<code>WHERE user_id = 1001</code>）</li><li><strong>范围条件的列放等值列后面</strong>（<code>WHERE created_at &gt;= &#39;...&#39;</code>）</li><li>排序的列尽量和索引顺序一致</li></ul><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">KEY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> idx_app_status_time (app_name, status_code, created_at)</span></span></code></pre></div><p>适合查 <code>WHERE app_name=&#39;api&#39; AND status_code=500 AND created_at&gt;=&#39;...&#39;</code>——app_name 和 status_code 是等值放前面，created_at 是范围放后面。</p><p><strong>如果反过来</strong>，范围条件放前面：</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">KEY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> idx_time_app_status (created_at, app_name, status_code)</span></span></code></pre></div><p><code>WHERE created_at &gt;= &#39;...&#39; AND app_name=&#39;api&#39;</code>——created_at 是范围，匹配后 app_name 在树里是分散的，用不上索引。这是联合索引设计最容易踩的坑。</p><h2 id="四、索引什么时候失效" tabindex="-1">四、索引什么时候失效 <a class="header-anchor" href="#四、索引什么时候失效" aria-label="Permalink to &quot;四、索引什么时候失效&quot;">​</a></h2><p>建了索引不代表查询一定用它。几种常见情况索引会失效：</p><h3 id="函数和运算" tabindex="-1">函数和运算 <a class="header-anchor" href="#函数和运算" aria-label="Permalink to &quot;函数和运算&quot;">​</a></h3><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> DATE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(created_at) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;2026-06-23&#39;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     -- ✗ 对列用了函数，失效</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> created_at </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;2026-06-23&#39;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  AND</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> created_at </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;2026-06-24&#39;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           -- ✓ 改成范围，能用索引</span></span></code></pre></div><p>对索引列套函数、做运算，索引失效。把条件改成等价的不带函数的形式。</p><h3 id="隐式类型转换" tabindex="-1">隐式类型转换 <a class="header-anchor" href="#隐式类型转换" aria-label="Permalink to &quot;隐式类型转换&quot;">​</a></h3><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> user_id </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;1001&#39;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     -- user_id 是 BIGINT，传字符串</span></span></code></pre></div><p>MySQL 会把 <code>&#39;1001&#39;</code> 转成数字比较，但这个转换可能让索引失效。传值时类型要对上——数字列传数字、字符串列传字符串。</p><h3 id="like-前通配" tabindex="-1">LIKE 前通配 <a class="header-anchor" href="#like-前通配" aria-label="Permalink to &quot;LIKE 前通配&quot;">​</a></h3><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> hostname </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">LIKE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;web-%&#39;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     -- ✓ 前缀固定，走索引</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> hostname </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">LIKE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;%web&#39;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      -- ✗ 前面通配，失效</span></span></code></pre></div><p>B+Tree 按前缀排序定位，前面是通配符没法定位，只能全扫。</p><h3 id="or-的坑" tabindex="-1">OR 的坑 <a class="header-anchor" href="#or-的坑" aria-label="Permalink to &quot;OR 的坑&quot;">​</a></h3><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> user_id </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1001</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> OR</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> app_name </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;api&#39;</span></span></code></pre></div><p><code>OR</code> 两边都要有索引才走索引，一边没有就退化成全表扫。这种情况考虑用 <code>UNION ALL</code> 拆成两个走索引的查询。</p><h3 id="不等于和-not-in" tabindex="-1">不等于和 NOT IN <a class="header-anchor" href="#不等于和-not-in" aria-label="Permalink to &quot;不等于和 NOT IN&quot;">​</a></h3><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> status</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> !=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> user_id </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">NOT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> IN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>不等于、NOT IN 这类条件，索引通常帮不上——B+Tree 适合找&quot;等于某值&quot;或&quot;在某范围&quot;，找&quot;不等于&quot;得扫遍所有行。</p><h2 id="五、索引不是越多越好" tabindex="-1">五、索引不是越多越好 <a class="header-anchor" href="#五、索引不是越多越好" aria-label="Permalink to &quot;五、索引不是越多越好&quot;">​</a></h2><p>每个索引都是一棵 B+Tree，占存储空间。写数据时（INSERT/UPDATE/DELETE）所有相关索引都要更新，索引多了写入变慢。</p><p>原则：<strong>查得多建索引，写得多慎建</strong>。高频查询的 WHERE、JOIN、ORDER BY 条件建索引，很少查的列别建。建了不用的索引是负担。</p><h2 id="索引原理之后" tabindex="-1">索引原理之后 <a class="header-anchor" href="#索引原理之后" aria-label="Permalink to &quot;索引原理之后&quot;">​</a></h2><p>知道了索引怎么工作、最左前缀、为什么会失效。但实际某条查询到底走了没走索引、扫了多少行，光靠想不准。下一篇讲 EXPLAIN——让 MySQL 自己说出这条查询的实际执行计划。</p>`,60)])])}const g=a(h,[["render",n]]);export{c as __pageData,g as default};
